sys_script_include.script:
var PlacementUtils = Class.create();
PlacementUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    checkEligibility: function() {

        var studentId = this.getParameter('sysparm_student');
        var driveId = this.getParameter('sysparm_drive');

        var studentGR = new GlideRecord('x_2081486_placem_0_u_student');
        if (!studentGR.get(studentId))
            return 'Student not found';

        var driveGR = new GlideRecord('x_2081486_placem_0_u_drive');
        if (!driveGR.get(driveId))
            return 'Drive not found';

        var studentCGPA = parseFloat(studentGR.getValue('cgpa'));
        var driveCGPA = parseFloat(driveGR.getValue('min_cgpa'));

        if (studentCGPA >= driveCGPA)
            return 'Eligible';

        return 'Not Eligible';
    },

    type: 'PlacementUtils'
});
